('bookkeeper-moex-01107', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於X1 年底舉借五年期銀行借款$500,000，利率10%，約定自X2 年至X6 年間每年年底向銀行支付 $131,899即償付所有本息。關於該筆借款，甲公司於X2年底應認列之長期負債金額為（答案四捨五入至元）：', '["$500,000", "$418,101", "$328,012", "$228,914"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
