  ('bookkeeper-moex-01110', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司X1年初之設備總額$27,000，累計折舊為$3,000，X1年底之設備總額$30,000，累計折舊為$5,000， X1年之設備折舊費用為$4,000，設備處分損失為$1,000。該公司X1年新購設備$7,000，且所有處分與購 置均發生於年底並以現金交割，則該公司X1年處分設備之現金流入為：', '["$1,000", "$2,000", "$3,000", "$4,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
